// SLA113 Game Engine — Neon Fish Arena
// Template: Fish Shooting
// Auto-generated by SLA113 Build Pipeline

const GAME_CONFIG = {
  "type": "fish_shooting",
  "name": "Neon Fish Arena",
  "version": "1.0.0",
  "built_by": "SLA113"
};
const ASSET_MANIFEST = [];

(async () => {
  const app = new PIXI.Application({ width: window.innerWidth, height: window.innerHeight, backgroundColor: 0x001020, antialias: true });
  document.body.appendChild(app.view);
  document.getElementById('loading').style.display = 'none';
  window.addEventListener('resize', () => app.renderer.resize(window.innerWidth, window.innerHeight));

  const W = app.screen.width, H = app.screen.height;
  let score = 0, ammo = 100, credits = 1000;

  // Ocean background with gradient
  const bg = new PIXI.Graphics();
  bg.beginFill(0x001830).drawRect(0, 0, W, H).endFill();
  for (let y = 0; y < H; y += 3) {
    bg.lineStyle(1, 0x002040 + Math.floor(y/H * 0x30));
    bg.moveTo(0, y).lineTo(W, y);
  }
  app.stage.addChild(bg);

  // Bubbles
  const bubbles = [];
  for (let i = 0; i < 30; i++) {
    const b = new PIXI.Graphics();
    b.beginFill(0x00c8ff, 0.15).drawCircle(0, 0, 2 + Math.random() * 6).endFill();
    b.x = Math.random() * W; b.y = Math.random() * H;
    b.vy = -0.3 - Math.random() * 0.5;
    b.vx = (Math.random() - 0.5) * 0.3;
    app.stage.addChild(b); bubbles.push(b);
  }

  // Fish entities
  const fishColors = [0xff6600, 0xd4af37, 0x00c8ff, 0xff4444, 0x44ff44, 0x9966ff, 0xff00ff];
  const fishValues = [10, 25, 50, 100, 200, 500, 1000];
  const fish = [];

  function spawnFish() {
    const tier = Math.floor(Math.random() * fishColors.length);
    const g = new PIXI.Graphics();
    const size = 15 + tier * 5;
    g.beginFill(fishColors[tier], 0.9);
    g.moveTo(size, 0).lineTo(-size, -size*0.6).lineTo(-size*0.5, 0).lineTo(-size, size*0.6).closePath();
    g.endFill();
    // Eye
    g.beginFill(0xffffff).drawCircle(size*0.4, -size*0.15, 3).endFill();
    g.beginFill(0x000000).drawCircle(size*0.5, -size*0.15, 1.5).endFill();

    const fromLeft = Math.random() > 0.5;
    g.x = fromLeft ? -40 : W + 40;
    g.y = 80 + Math.random() * (H - 180);
    g.vx = (fromLeft ? 1 : -1) * (0.5 + Math.random() * (1 + tier * 0.3));
    g.vy = (Math.random() - 0.5) * 0.5;
    g.scale.x = fromLeft ? 1 : -1;
    g.tier = tier; g.hp = 1 + tier; g.value = fishValues[tier];
    g.interactive = true; g.cursor = 'crosshair';
    g.on('pointerdown', () => {
      if (ammo <= 0) return;
      ammo--;
      g.hp--;
      g.alpha = 0.5; setTimeout(() => { g.alpha = g.hp > 0 ? 0.9 : 0; }, 100);
      if (g.hp <= 0) {
        score += g.value; credits += g.value;
        document.getElementById('score').textContent = credits;
        // Explosion
        for (let p = 0; p < 8; p++) {
          const particle = new PIXI.Graphics();
          particle.beginFill(fishColors[tier]).drawCircle(0,0,2).endFill();
          particle.x = g.x; particle.y = g.y;
          particle.vx = (Math.random()-0.5)*5; particle.vy = (Math.random()-0.5)*5;
          particle.life = 30; app.stage.addChild(particle); bubbles.push(particle);
        }
        g.x = -999;
      }
    });
    app.stage.addChild(g); fish.push(g);
  }

  for (let i = 0; i < 12; i++) spawnFish();
  setInterval(spawnFish, 2000);
  setInterval(() => { ammo = Math.min(ammo + 5, 100); }, 1000);

  // Crosshair
  const crosshair = new PIXI.Graphics();
  crosshair.lineStyle(1, 0xff0000, 0.8);
  crosshair.drawCircle(0,0,15).moveTo(-20,0).lineTo(20,0).moveTo(0,-20).lineTo(0,20);
  crosshair.zIndex = 1000; app.stage.addChild(crosshair);
  app.stage.sortableChildren = true;
  app.view.addEventListener('mousemove', e => { crosshair.x = e.offsetX; crosshair.y = e.offsetY; });

  // HUD update
  const hudAmmo = document.createElement('div');
  hudAmmo.style.cssText = 'position:fixed;bottom:16px;left:16px;color:#00c8ff;font:11px monospace;text-transform:uppercase;letter-spacing:2px;z-index:100';
  document.body.appendChild(hudAmmo);

  app.ticker.add(() => {
    fish.forEach(f => {
      f.x += f.vx; f.y += f.vy + Math.sin(Date.now()/500 + f.x) * 0.3;
      if (f.x < -80 || f.x > W+80) { f.x = f.vx > 0 ? -40 : W+40; f.y = 80+Math.random()*(H-180); }
    });
    bubbles.forEach(b => {
      if (b.life !== undefined) { b.x += b.vx; b.y += b.vy; b.life--; b.alpha = b.life/30; if(b.life<=0) b.visible=false; }
      else { b.x += b.vx; b.y += b.vy; if(b.y < -10) { b.y = H+10; b.x = Math.random()*W; } }
    });
    hudAmmo.textContent = `AMMO: ${ammo} | CREDITS: ${credits} | KILLS: ${score}`;
  });

  console.log('[SLA113] Fish Shooting initialized');
})();
